import {
    BrowserRouter,
    Routes,
    Route
}

from "react-router-dom";

import Home from "./pages/Home";

import BookingPage from "./pages/BookingPage";

import RegisterPage from "./pages/RegisterPage";

import LoginPage from "./pages/LoginPage";

import MyBookings from "./pages/MyBookings";

function App() {

    return (

        <BrowserRouter>

            <Routes>

                <Route
                    path="/"
                    element={<Home />}
                />

                <Route
                    path="/booking/:id"
                    element={<BookingPage />}
                />

                <Route
                    path="/register"
                    element={<RegisterPage />}
                />

                <Route
                    path="/login"
                    element={<LoginPage />}
                />

                <Route
    path="/my-bookings"
    element={<MyBookings />}
/>

            </Routes>

        </BrowserRouter>
    );
}

export default App;
